@posts_bp.route("/posts/<int:post_id>/delete", methods=["POST"])
def delete_post(post_id):
    post = Post.query.get_or_404(post_id)
    # TODO: 接入登录系统后，这里需要验证当前用户是否是发帖人

    image_records = post.images.all()
    image_urls = {image.image_url for image in image_records if image.image_url}

    for image_url in image_urls:
        _delete_local_image_file(image_url)

    db.session.delete(post)
    db.session.commit()
    flash("帖子已删除")
    return redirect(url_for("posts.list_posts"))


@posts_bp.route("/posts/<int:post_id>/edit", methods=["GET", "POST"])
def edit_post(post_id):
    post = Post.query.get_or_404(post_id)
    # TODO: 接入登录系统后，这里需要验证当前用户是否是发帖人

    if request.method == "GET":
        return render_template("posts/edit.html", post=post, form_data={})

    title = (request.form.get("title") or "").strip()
    rent = _to_decimal(request.form.get("rent"))
    location = (request.form.get("location") or "").strip()
    uploaded_files = [
        file
        for file in request.files.getlist("images")
        if file and (file.filename or "").strip()
    ]
    delete_image_ids = {
        int(image_id)
        for image_id in request.form.getlist("delete_images")
        if (image_id or "").strip().isdigit()
    }
    allowed_extensions = {"jpg", "jpeg", "png", "webp"}
    existing_images = post.images.all()
    images_by_id = {image.id: image for image in existing_images}
    images_to_delete = [images_by_id[image_id] for image_id in delete_image_ids if image_id in images_by_id]
    remaining_image_count = len(existing_images) - len(images_to_delete)

    if not title or rent is None or not location:
        flash("标题、租金和位置为必填项")
        return render_template("posts/edit.html", post=post, form_data=request.form), 400

    if remaining_image_count + len(uploaded_files) > 6:
        flash("最多上传6张")
        return render_template("posts/edit.html", post=post, form_data=request.form), 400

    post.title = title
    post.rent = rent
    post.location = location
    post.nearby_school = (request.form.get("nearby_school") or "").strip() or None
    post.community_name = (request.form.get("community_name") or "").strip() or None
    post.layout = (request.form.get("layout") or "").strip() or None
    post.area = _to_decimal(request.form.get("area"))
    post.poster_gender = (request.form.get("poster_gender") or "").strip() or None
    post.poster_age = _to_int(request.form.get("poster_age"))
    post.poster_occupation_or_school = (
        (request.form.get("poster_occupation_or_school") or "").strip() or None
    )
    post.poster_intro = (request.form.get("poster_intro") or "").strip() or None
    post.expected_schedule = (request.form.get("expected_schedule") or "").strip() or None
    post.cleaning_frequency = (request.form.get("cleaning_frequency") or "").strip() or None
    post.hobbies = _normalize_hobbies(request.form.get("hobbies", ""))
    post.custom_requirements = (request.form.get("custom_requirements") or "").strip() or None

    for existing_image in images_to_delete:
        _delete_local_image_file(existing_image.image_url)
        db.session.delete(existing_image)

    if uploaded_files:
        upload_folder = current_app.config.get("UPLOAD_FOLDER") or os.path.join(
            current_app.root_path, "static", "uploads"
        )
        os.makedirs(upload_folder, exist_ok=True)

        saved_images = []
        for file in uploaded_files:
            filename = secure_filename(file.filename or "")
            if "." not in filename:
                flash("只接受jpg/jpeg/png/webp格式")
                return render_template("posts/edit.html", post=post, form_data=request.form), 400

            ext = filename.rsplit(".", 1)[1].lower()
            if ext not in allowed_extensions:
                flash("只接受jpg/jpeg/png/webp格式")
                return render_template("posts/edit.html", post=post, form_data=request.form), 400

            file.stream.seek(0, os.SEEK_END)
            file_size = file.stream.tell()
            file.stream.seek(0)
            if file_size > 5 * 1024 * 1024:
                flash("图片太大，请压缩后再上传")
                return render_template("posts/edit.html", post=post, form_data=request.form), 400

            new_filename = secure_filename(f"{uuid4().hex}.{ext}")
            save_path = os.path.join(upload_folder, new_filename)
            file.save(save_path)
            saved_images.append(f"/static/uploads/{new_filename}")

        remaining_images = [image for image in existing_images if image not in images_to_delete]
        max_sort_order = max([(image.sort_order or 0) for image in remaining_images], default=-1)

        for offset, image_url in enumerate(saved_images, start=1):
            db.session.add(
                PostImage(
                    post_id=post.id,
                    image_url=image_url,
                    sort_order=max_sort_order + offset,
                )
            )

    db.session.commit()
    flash("帖子更新成功")
    return redirect(url_for("posts.post_detail", post_id=post.id))


@posts_bp.route("/posts/<int:post_id>/favorite", methods=["POST"])
def toggle_favorite(post_id):
    post = Post.query.get_or_404(post_id)
    user_id = _current_user_id()

    favorite = Favorite.query.filter_by(user_id=user_id, post_id=post.id).first()
    if favorite:
        db.session.delete(favorite)
        flash("已取消收藏")
    else:
        db.session.add(Favorite(user_id=user_id, post_id=post.id))
        flash("已加入收藏")

    db.session.commit()
    return redirect(url_for("posts.post_detail", post_id=post.id))

{% extends "base.html" %}

{% block title %}帖子详情{% endblock %}

{% block content %}
<div class="card">
    <h2>{{ post.title }}</h2>
    <p class="muted">发布人：<a href="/user/{{ post.user_id }}">{{ post.author.username }}</a> ｜ 发布时间：{{ post.created_at }}</p>

    <div id="post-carousel" class="post-carousel">
        <div id="carousel-track" class="carousel-track">
            {% if images %}
                {% for image in images %}
                    <div class="carousel-slide">
                        <img src="{{ image.image_url }}" alt="帖子图片">
                    </div>
                {% endfor %}
            {% else %}
                <div class="carousel-slide">
                    <img src="https://picsum.photos/seed/roommate-detail/900/600" alt="默认图片">
                </div>
            {% endif %}
        </div>

        {% if images and images|length > 1 %}
            <button id="carousel-prev" class="carousel-btn prev" type="button" aria-label="上一张">&#10094;</button>
            <button id="carousel-next" class="carousel-btn next" type="button" aria-label="下一张">&#10095;</button>
            <div id="carousel-dots" class="carousel-dots"></div>
        {% endif %}
    </div>

    <div>
        <p><strong>租金：</strong>{{ post.rent }}</p>
        <p><strong>位置：</strong>{{ post.location }}</p>
        <p><strong>附近学校：</strong>{{ post.nearby_school or '-' }}</p>
        <p><strong>小区名称：</strong>{{ post.community_name or '-' }}</p>
        <p><strong>户型：</strong>{{ post.layout or '-' }}</p>
        <p><strong>面积（㎡）：</strong>{{ post.area or '-' }}</p>
        <p><strong>个人介绍：</strong>{{ post.poster_intro or '-' }}</p>
        <p><strong>兴趣爱好：</strong>{{ post.hobbies or '-' }}</p>
        <p><strong>期望室友作息时间：</strong>{{ post.expected_schedule or '-' }}</p>
        <p><strong>家务分配：</strong>{{ post.cleaning_frequency or '-' }}</p>
        <p><strong>对室友的期望：</strong>{{ post.custom_requirements or '-' }}</p>
    </div>

    <div class="actions">
        <form method="post" action="{{ url_for('posts.toggle_favorite', post_id=post.id) }}">
            <button class="btn {% if is_favorite %}danger{% endif %}" type="submit">
                {% if is_favorite %}取消收藏{% else %}收藏{% endif %}
            </button>
        </form>
        <a class="btn secondary" href="#appointment">预约看房</a>
        <a class="btn secondary" href="#message">发私信</a>
    </div>
</div>

<div class="card" id="appointment">
    <h3>预约看房</h3>
    <p class="muted">这里先预留预约入口，后续可以接 Appointment 模块。</p>
</div>

<div class="card" id="message">
    <h3>发私信</h3>
    <p class="muted">这里先预留私信入口，后续可以接 Message 模块。</p>
</div>

<a href="{{ url_for('posts.list_posts') }}">返回列表</a>

<style>
    .post-carousel {
        position: relative;
        width: 100%;
        max-width: 600px;
        overflow: hidden;
        margin-bottom: 16px;
    }
    .carousel-track {
        display: flex;
        transition: transform 0.25s ease;
    }
    .carousel-slide {
        min-width: 100%;
        box-sizing: border-box;
    }
    .carousel-slide img {
        width: 100%;
        height: 300px;
        object-fit: cover;
        border-radius: 8px;
        display: block;
    }
    .carousel-btn {
        position: absolute;
        top: 50%;
        transform: translateY(-50%);
        border: 0;
        width: 32px;
        height: 32px;
        border-radius: 999px;
        background: rgba(0, 0, 0, 0.45);
        color: #fff;
        cursor: pointer;
        line-height: 1;
    }
    .carousel-btn.prev {
        left: 8px;
    }
    .carousel-btn.next {
        right: 8px;
    }
    .carousel-dots {
        display: flex;
        justify-content: center;
        gap: 6px;
        margin-top: 8px;
    }
    .carousel-dot {
        width: 8px;
        height: 8px;
        border-radius: 50%;
        border: 0;
        padding: 0;
        background: #d4d4d8;
        cursor: pointer;
    }
    .carousel-dot.active {
        background: #2563eb;
    }
</style>

<script>
    (function () {
        var carousel = document.getElementById("post-carousel");
        var track = document.getElementById("carousel-track");
        var prevBtn = document.getElementById("carousel-prev");
        var nextBtn = document.getElementById("carousel-next");
        var dotsContainer = document.getElementById("carousel-dots");
        var slides = track ? track.querySelectorAll(".carousel-slide") : [];
        var currentIndex = 0;
        var startX = 0;
        var deltaX = 0;

        function updateCarousel() {
            if (!track || !slides.length) {
                return;
            }
            track.style.transform = "translateX(-" + (currentIndex * 100) + "%)";
            if (!dotsContainer) {
                return;
            }
            var dots = dotsContainer.querySelectorAll(".carousel-dot");
            for (var i = 0; i < dots.length; i += 1) {
                dots[i].classList.toggle("active", i === currentIndex);
            }
        }

        if (slides.length > 1 && dotsContainer) {
            for (var d = 0; d < slides.length; d += 1) {
                (function (dotIndex) {
                    var dot = document.createElement("button");
                    dot.type = "button";
                    dot.className = "carousel-dot" + (dotIndex === 0 ? " active" : "");
                    dot.setAttribute("aria-label", "切换到第" + (dotIndex + 1) + "张");
                    dot.addEventListener("click", function () {
                        currentIndex = dotIndex;
                        updateCarousel();
                    });
                    dotsContainer.appendChild(dot);
                })(d);
            }
        }

        if (prevBtn) {
            prevBtn.addEventListener("click", function () {
                currentIndex = (currentIndex - 1 + slides.length) % slides.length;
                updateCarousel();
            });
        }

        if (nextBtn) {
            nextBtn.addEventListener("click", function () {
                currentIndex = (currentIndex + 1) % slides.length;
                updateCarousel();
            });
        }

        if (carousel && slides.length > 1) {
            carousel.addEventListener("touchstart", function (event) {
                startX = event.touches[0].clientX;
                deltaX = 0;
            }, { passive: true });

            carousel.addEventListener("touchmove", function (event) {
                deltaX = event.touches[0].clientX - startX;
            }, { passive: true });

            carousel.addEventListener("touchend", function () {
                if (Math.abs(deltaX) < 40) {
                    return;
                }
                if (deltaX < 0) {
                    currentIndex = (currentIndex + 1) % slides.length;
                } else {
                    currentIndex = (currentIndex - 1 + slides.length) % slides.length;
                }
                updateCarousel();
            });
        }

        updateCarousel();
    })();
</script>
{% endblock %}

{% extends "base.html" %}

{% block title %}帖子详情{% endblock %}

{% block content %}
<div class="card">
    <div class="post-header">
        <h2>{{ post.title }}</h2>
        <div class="post-actions-top">
            <a class="btn secondary inline" href="/posts/{{ post.id }}/edit">编辑</a>
            <form method="post" action="/posts/{{ post.id }}/delete" onsubmit="return confirm('确定要删除这个帖子吗？');">
                <button class="btn danger inline delete-icon-btn" type="submit" aria-label="删除帖子" title="删除帖子">️</button>
            </form>
        </div>
    </div>
    <p class="muted">发布人：<a href="/user/{{ post.user_id }}">{{ post.author.username }}</a> ｜ 发布时间：{{ post.created_at }}</p>

    <div id="post-carousel" class="post-carousel">
        <div id="carousel-track" class="carousel-track">
            {% if images %}
                {% for image in images %}
                    <div class="carousel-slide">
                        <img src="{{ image.image_url }}" alt="帖子图片">
                    </div>
                {% endfor %}
            {% else %}
                <div class="carousel-slide">
                    <img src="https://picsum.photos/seed/roommate-detail/900/600" alt="默认图片">
                </div>
            {% endif %}
        </div>

        {% if images and images|length > 1 %}
            <button id="carousel-prev" class="carousel-btn prev" type="button" aria-label="上一张">&#10094;</button>
            <button id="carousel-next" class="carousel-btn next" type="button" aria-label="下一张">&#10095;</button>
            <div id="carousel-dots" class="carousel-dots"></div>
        {% endif %}
    </div>

    <div>
        <p><strong>租金：</strong>{{ post.rent }}</p>
        <p><strong>位置：</strong>{{ post.location }}</p>
        <p><strong>附近学校：</strong>{{ post.nearby_school or '-' }}</p>
        <p><strong>小区名称：</strong>{{ post.community_name or '-' }}</p>
        <p><strong>户型：</strong>{{ post.layout or '-' }}</p>
        <p><strong>面积（㎡）：</strong>{{ post.area or '-' }}</p>
        <p><strong>个人介绍：</strong>{{ post.poster_intro or '-' }}</p>
        <p><strong>兴趣爱好：</strong>{{ post.hobbies or '-' }}</p>
        <p><strong>期望室友作息时间：</strong>{{ post.expected_schedule or '-' }}</p>
        <p><strong>家务分配：</strong>{{ post.cleaning_frequency or '-' }}</p>
        <p><strong>对室友的期望：</strong>{{ post.custom_requirements or '-' }}</p>
    </div>

    <div class="actions">
        <form method="post" action="{{ url_for('posts.toggle_favorite', post_id=post.id) }}">
            <button class="btn {% if is_favorite %}danger{% endif %}" type="submit">
                {% if is_favorite %}取消收藏{% else %}收藏{% endif %}
            </button>
        </form>
        <a class="btn secondary" href="#appointment">预约看房</a>
        <a class="btn secondary" href="#message">发私信</a>
    </div>
</div>

<div class="card" id="appointment">
    <h3>预约看房</h3>
    <p class="muted">这里先预留预约入口，后续可以接 Appointment 模块。</p>
</div>

<div class="card" id="message">
    <h3>发私信</h3>
    <p class="muted">这里先预留私信入口，后续可以接 Message 模块。</p>
</div>

<a href="{{ url_for('posts.list_posts') }}">返回列表</a>

